package config

import (
	"os"
	"strconv"
	"time"
)

// Config holds application configuration
type Config struct {
	// Server
	Port string
	Env  string

	// Database
	DBPath         string
	MigrationsPath string

	// JWT
	JWTSecret      string
	JWTExpiryHours int

	// CORS
	CORSAllowedOrigins []string

	// Rate Limiting
	RateLimitRequests       int
	RateLimitWindowMinutes  int

	// Logging
	LogLevel       string
	EnableSQLLog   bool

	// Database
	DBQueryTimeout time.Duration
}

// Load reads configuration from environment variables
func Load() *Config {
	cfg := &Config{
		Port:                    getEnv("PORT", "8080"),
		Env:                     getEnv("ENV", "development"),
		DBPath:                  getEnv("DB_PATH", "./data/sprintspark.db"),
		MigrationsPath:          getEnv("MIGRATIONS_PATH", "./internal/db/migrations"),
		JWTSecret:               getEnv("JWT_SECRET", "change-this-to-a-secure-random-string-in-production"),
		JWTExpiryHours:          getEnvAsInt("JWT_EXPIRY_HOURS", 24),
		CORSAllowedOrigins:      getEnvAsSlice("CORS_ALLOWED_ORIGINS", []string{"http://localhost:5173", "http://localhost:3000"}),
		RateLimitRequests:       getEnvAsInt("RATE_LIMIT_REQUESTS", 100),
		RateLimitWindowMinutes:  getEnvAsInt("RATE_LIMIT_WINDOW_MINUTES", 15),
		LogLevel:                getEnv("LOG_LEVEL", "info"),
		EnableSQLLog:            getEnv("ENV", "development") == "development" || getEnv("ENABLE_SQL_LOG", "false") == "true",
		DBQueryTimeout:          time.Duration(getEnvAsInt("DB_QUERY_TIMEOUT_SECONDS", 5)) * time.Second,
	}

	// Validate critical configuration
	if cfg.Env == "production" && cfg.JWTSecret == "change-this-to-a-secure-random-string-in-production" {
		logger := MustInitLogger(cfg.Env, cfg.LogLevel)
		logger.Fatal("JWT_SECRET must be set in production environment")
	}

	return cfg
}

// JWTExpiry returns the JWT expiry duration
func (c *Config) JWTExpiry() time.Duration {
	return time.Duration(c.JWTExpiryHours) * time.Hour
}

// getEnv reads an environment variable or returns a default value
func getEnv(key, defaultValue string) string {
	if value := os.Getenv(key); value != "" {
		return value
	}
	return defaultValue
}

// getEnvAsInt reads an environment variable as int or returns a default value
func getEnvAsInt(key string, defaultValue int) int {
	valueStr := os.Getenv(key)
	if valueStr == "" {
		return defaultValue
	}
	value, err := strconv.Atoi(valueStr)
	if err != nil {
		// Silently use default - logger not available yet during config load
		return defaultValue
	}
	return value
}

// getEnvAsSlice reads an environment variable as comma-separated values
func getEnvAsSlice(key string, defaultValue []string) []string {
	valueStr := os.Getenv(key)
	if valueStr == "" {
		return defaultValue
	}

	var result []string
	for _, v := range splitCommaSeparated(valueStr) {
		if trimmed := trimSpace(v); trimmed != "" {
			result = append(result, trimmed)
		}
	}

	if len(result) == 0 {
		return defaultValue
	}
	return result
}

// splitCommaSeparated splits a string by commas
func splitCommaSeparated(s string) []string {
	var parts []string
	current := ""
	for _, ch := range s {
		if ch == ',' {
			parts = append(parts, current)
			current = ""
		} else {
			current += string(ch)
		}
	}
	if current != "" {
		parts = append(parts, current)
	}
	return parts
}

// trimSpace removes leading and trailing whitespace
func trimSpace(s string) string {
	start := 0
	end := len(s)

	for start < end && (s[start] == ' ' || s[start] == '\t' || s[start] == '\n' || s[start] == '\r') {
		start++
	}

	for end > start && (s[end-1] == ' ' || s[end-1] == '\t' || s[end-1] == '\n' || s[end-1] == '\r') {
		end--
	}

	return s[start:end]
}

package config

import (
	"testing"
	"time"
)

func TestGetEnv(t *testing.T) {
	tests := []struct {
		name         string
		key          string
		defaultValue string
		envValue     string
		setEnv       bool
		want         string
	}{
		{
			name:         "returns default when env not set",
			key:          "TEST_GET_ENV_MISSING",
			defaultValue: "default_val",
			setEnv:       false,
			want:         "default_val",
		},
		{
			name:         "returns env value when set",
			key:          "TEST_GET_ENV_SET",
			defaultValue: "default_val",
			envValue:     "custom_val",
			setEnv:       true,
			want:         "custom_val",
		},
		{
			name:         "returns default when env is empty string",
			key:          "TEST_GET_ENV_EMPTY",
			defaultValue: "fallback",
			envValue:     "",
			setEnv:       true,
			want:         "fallback",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if tt.setEnv {
				t.Setenv(tt.key, tt.envValue)
			}

			got := getEnv(tt.key, tt.defaultValue)
			if got != tt.want {
				t.Errorf("getEnv(%q, %q) = %q, want %q", tt.key, tt.defaultValue, got, tt.want)
			}
		})
	}
}

func TestGetEnvAsInt(t *testing.T) {
	tests := []struct {
		name         string
		key          string
		defaultValue int
		envValue     string
		setEnv       bool
		want         int
	}{
		{
			name:         "returns default when env not set",
			key:          "TEST_INT_MISSING",
			defaultValue: 42,
			setEnv:       false,
			want:         42,
		},
		{
			name:         "returns parsed int when valid",
			key:          "TEST_INT_VALID",
			defaultValue: 10,
			envValue:     "100",
			setEnv:       true,
			want:         100,
		},
		{
			name:         "returns default when env is empty",
			key:          "TEST_INT_EMPTY",
			defaultValue: 5,
			envValue:     "",
			setEnv:       true,
			want:         5,
		},
		{
			name:         "returns default when env is not a number",
			key:          "TEST_INT_INVALID",
			defaultValue: 7,
			envValue:     "not-a-number",
			setEnv:       true,
			want:         7,
		},
		{
			name:         "handles zero value",
			key:          "TEST_INT_ZERO",
			defaultValue: 99,
			envValue:     "0",
			setEnv:       true,
			want:         0,
		},
		{
			name:         "handles negative value",
			key:          "TEST_INT_NEGATIVE",
			defaultValue: 10,
			envValue:     "-5",
			setEnv:       true,
			want:         -5,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if tt.setEnv {
				t.Setenv(tt.key, tt.envValue)
			}

			got := getEnvAsInt(tt.key, tt.defaultValue)
			if got != tt.want {
				t.Errorf("getEnvAsInt(%q, %d) = %d, want %d", tt.key, tt.defaultValue, got, tt.want)
			}
		})
	}
}

func TestGetEnvAsSlice(t *testing.T) {
	tests := []struct {
		name         string
		key          string
		defaultValue []string
		envValue     string
		setEnv       bool
		want         []string
	}{
		{
			name:         "returns default when env not set",
			key:          "TEST_SLICE_MISSING",
			defaultValue: []string{"a", "b"},
			setEnv:       false,
			want:         []string{"a", "b"},
		},
		{
			name:         "parses comma-separated values",
			key:          "TEST_SLICE_CSV",
			defaultValue: []string{"default"},
			envValue:     "http://localhost:3000,http://localhost:5173",
			setEnv:       true,
			want:         []string{"http://localhost:3000", "http://localhost:5173"},
		},
		{
			name:         "trims whitespace around values",
			key:          "TEST_SLICE_WHITESPACE",
			defaultValue: []string{"default"},
			envValue:     " foo , bar , baz ",
			setEnv:       true,
			want:         []string{"foo", "bar", "baz"},
		},
		{
			name:         "single value without comma",
			key:          "TEST_SLICE_SINGLE",
			defaultValue: []string{"default"},
			envValue:     "http://example.com",
			setEnv:       true,
			want:         []string{"http://example.com"},
		},
		{
			name:         "returns default when env is empty",
			key:          "TEST_SLICE_EMPTY",
			defaultValue: []string{"fallback"},
			envValue:     "",
			setEnv:       true,
			want:         []string{"fallback"},
		},
		{
			name:         "returns default when only commas and whitespace",
			key:          "TEST_SLICE_ONLY_COMMAS",
			defaultValue: []string{"default"},
			envValue:     ", , ,",
			setEnv:       true,
			want:         []string{"default"},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if tt.setEnv {
				t.Setenv(tt.key, tt.envValue)
			}

			got := getEnvAsSlice(tt.key, tt.defaultValue)

			if len(got) != len(tt.want) {
				t.Fatalf("getEnvAsSlice(%q) returned %d elements, want %d: got=%v, want=%v",
					tt.key, len(got), len(tt.want), got, tt.want)
			}
			for i := range got {
				if got[i] != tt.want[i] {
					t.Errorf("getEnvAsSlice(%q)[%d] = %q, want %q", tt.key, i, got[i], tt.want[i])
				}
			}
		})
	}
}

func TestSplitCommaSeparated(t *testing.T) {
	tests := []struct {
		name  string
		input string
		want  []string
	}{
		{
			name:  "simple split",
			input: "a,b,c",
			want:  []string{"a", "b", "c"},
		},
		{
			name:  "single element",
			input: "only",
			want:  []string{"only"},
		},
		{
			name:  "empty string",
			input: "",
			want:  nil,
		},
		{
			name:  "trailing comma produces empty trailing part",
			input: "a,b,",
			want:  []string{"a", "b"},
		},
		{
			name:  "leading comma produces empty leading part",
			input: ",a,b",
			want:  []string{"", "a", "b"},
		},
		{
			name:  "consecutive commas",
			input: "a,,b",
			want:  []string{"a", "", "b"},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := splitCommaSeparated(tt.input)

			if len(got) != len(tt.want) {
				t.Fatalf("splitCommaSeparated(%q) returned %d elements, want %d: got=%v, want=%v",
					tt.input, len(got), len(tt.want), got, tt.want)
			}
			for i := range got {
