func TestTrimSpace(t *testing.T) {
	tests := []struct {
		name  string
		input string
		want  string
	}{
		{
			name:  "no whitespace",
			input: "hello",
			want:  "hello",
		},
		{
			name:  "leading spaces",
			input: "   hello",
			want:  "hello",
		},
		{
			name:  "trailing spaces",
			input: "hello   ",
			want:  "hello",
		},
		{
			name:  "both sides",
			input: "  hello  ",
			want:  "hello",
		},
		{
			name:  "tabs and newlines",
			input: "\t\n hello \r\n\t",
			want:  "hello",
		},
		{
			name:  "all whitespace",
			input: "   \t\n  ",
			want:  "",
		},
